"use client";

import { useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  BASE_SEGMENTS,
  RECOVERY_SEGMENTS,
  DRAIN_SEGMENTS,
  VERDICT_NAME,
  segmentsMetrics,
  segmentsAI,
  type SegmentCard,
} from "@/features/customers/api/customers-segments-data";
import "./segments.css";

const PERIOD_LABELS = ["MTD", "Last month", "Last 90 days", "Last 12 months"];

export default function SegmentsPage() {
  const [periodIdx, setPeriodIdx] = useState(0);
  const { openBridge } = useBridge();

  return (
    <div className="customers-segments-page">
      <DeptHeader
        dept="customers"
        title="Segments"
        meta={
          <>
            <span className="live">Live</span> · 8 active segments · 2,140 customers · synced 2 min ago
          </>
        }
        actions={
          <>
            <button className="btn-util">Manage</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("customers")}
            >
              + Create segment
            </button>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Active segments</div>
          <div className="metric-v">{segmentsMetrics.active}</div>
          <div className="metric-s">{segmentsMetrics.activeSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Biggest segment</div>
          <div className="metric-v">{segmentsMetrics.biggest}</div>
          <div className="metric-s">{segmentsMetrics.biggestSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Needs recovery</div>
          <div className="metric-v red">{segmentsMetrics.recovery}</div>
          <div className="metric-s down">{segmentsMetrics.recoverySub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Healthy base</div>
          <div className="metric-v green">{segmentsMetrics.healthy}</div>
          <div className="metric-s up">{segmentsMetrics.healthySub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Value drains</div>
          <div className="metric-v red">{segmentsMetrics.drains}</div>
          <div className="metric-s down">{segmentsMetrics.drainsSub}</div>
        </div>
      </div>

      <AIStrip label={segmentsAI.label} meta={segmentsAI.meta} cards={segmentsAI.cards} />

      <SectionLabel>
        The base <span className="sl-note">— who you have, and what they&rsquo;re worth</span>
      </SectionLabel>
      <div className="seg-grid">
        {BASE_SEGMENTS.map((s) => <SegCard key={s.id} s={s} />)}
      </div>

      <SectionLabel>
        Needs recovery <span className="sl-note">— slipping past their cycle, act now</span>
      </SectionLabel>
      <div className="seg-grid">
        {RECOVERY_SEGMENTS.map((s) => <SegCard key={s.id} s={s} />)}
      </div>

      <SectionLabel>
        Value drains <span className="sl-note">— relationships that structurally lose money · Release</span>
      </SectionLabel>
      <div className="seg-grid">
        {DRAIN_SEGMENTS.map((s) => <SegCard key={s.id} s={s} drain />)}
      </div>

      <div className="foot-note">
        <span className="mk" />
        <p>
          Most tools only ever praise the top spenders. Magellan shows the <b>whole truth</b>: the engines that fund the business, the relationships slipping past their cycle, and — the part no dashboard wants to show you — the segments that <b>structurally lose money</b>. A segment is defined by a behavior threshold, not a guess, so each one is an action: <b>Protect</b> the VIPs, <b>Recover</b> the slipping, and <b>Release</b> the drains so retention spend flows to relationships that pay it back.
        </p>
      </div>
    </div>
  );
}

function SegCard({ s, drain }: { s: SegmentCard; drain?: boolean }) {
  const cardCls =
    s.id === "margin-drain"
      ? "seg-card negative"
      : drain
      ? "seg-card drain"
      : "seg-card";
  return (
    <div className={cardCls} style={{ ["--sc" as string]: s.accent } as React.CSSProperties}>
      <div className="sc-top">
        <div>
          <div className="sc-name">{s.name}</div>
          <div className="sc-def">{s.definition}</div>
        </div>
        <span className={`vpill ${s.verdict}`}>{VERDICT_NAME[s.verdict]}</span>
      </div>
      <div className="sc-count">
        <span className="n">{s.count}</span>
        <span className="u">customers</span>
      </div>
      <div className="sc-bar-wrap">
        <div className="sc-bar-cap">
          <span>{s.shareLabel}</span>
          <span>
            <b>{s.sharePct}</b> · {s.totalLabel}
          </span>
        </div>
        <div className="sc-bar">
          <div
            className={`sc-bar-fill${s.muted ? " muted" : ""}`}
            style={{ width: `${s.barPct}%`, background: s.muted ? undefined : s.barFill }}
          />
        </div>
      </div>
      <div className="sc-metrics">
        {s.metrics.map((m) => (
          <div key={m.label} className="sc-m">
            <div className="ml">{m.label}</div>
            <div className={`mv${m.tone ? " " + m.tone : ""}`}>{m.value}</div>
          </div>
        ))}
      </div>
      <div className="sc-foot">
        <div className="sc-move">
          {s.moves.map((m, i) => (
            <span key={i} className={m.tone ?? ""}>
              {m.text}
            </span>
          ))}
        </div>
        <span className="sc-view">View segment →</span>
      </div>
    </div>
  );
}
