/**
 * Mock data for Customers · Segments.
 *
 * Three sections — The base · Needs recovery · Value drains — each a
 * grid of segment cards with count, share-of-revenue bar, key metrics
 * and movement note. USD currency.
 */

export type SegmentVerdict = "protect" | "grow" | "watch" | "recover" | "release";

export interface SegmentCard {
  id: string;
  name: string;
  definition: string;
  verdict: SegmentVerdict;
  count: number;
  /** "$892K" — total revenue or revenue exposed for this segment. */
  totalLabel: string;
  /** Plain label e.g. "Share of revenue" / "Revenue exposed" / "Net contribution" / "Active revenue". */
  shareLabel: string;
  /** "24%" or "11%" — value displayed before the dollar amount. */
  sharePct: string;
  /** Bar width 0-100. */
  barPct: number;
  /** CSS gradient for the bar fill. */
  barFill: string;
  /** Whether the bar should render muted (drain segments). */
  muted?: boolean;
  /** Three metric cells (label/value). */
  metrics: Array<{ label: string; value: string; tone?: "green" | "red" }>;
  /** Two movement strings under the card. */
  moves: Array<{ text: string; tone?: "up" | "dn" | "pl" }>;
  /** Accent color hint for the left rail. */
  accent: string;
}

